#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span() to read header with zero-copy
    // The header size is 4 bytes (uint8_t + uint8_t + uint16_t)
    auto header_span = hexi::span<PacketHeader>(buffer, 1);
