struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // 1. Create a buffer_adaptor from the input buffer
    hexi::buffer_adaptor adaptor(buffer);

    // 2. Use buffer_adaptor's preview function to get the first byte (data_type) without advancing the read pointer
    uint8_t data_type = 0;
    adaptor.preview(&data_type, 1);

    // 3. Check the available data size using buffer_adaptor's size function
    const auto available_size = adaptor.size();

    // 4. Calculate the total expected data size
    // Minimum required: 1 (data_type) + 4 (item_count) = 5 bytes
    // Additional: item_count * sizeof(item) (4 or 4 bytes)
    // We'll validate this after reading item_count

    // 5. Read the item_count using binary_stream
    hexi::binary_stream stream(adaptor);
    uint32_t item_count = 0;
    stream >> item_count;

    // Validate available data size after reading item_count
    if (adaptor.size() < (5 + item_count * 4)) {
        throw std::runtime_error("Insufficient data in buffer");
    }

    // 6. Read the items based on data_type using binary_stream
    DataResult result;
    result.data_type = data_type;

    if (data_type == 0) {
        // Integers case
        result.int_items.resize(item_count);
        stream.get(result.int_items.data(), item_count);
    } else if (data_type == 1) {
        // Floats case
        result.float_items.resize(item_count);
        stream.get(result.float_items.data(), item_count);
    } else {
        // Invalid data_type - return empty result
        throw std::runtime_error("Invalid data type in buffer");
    }

    return result;
}
