bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // 1. Create a buffer_adaptor object from the provided buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // 2. Use the buffer_adaptor's size() method to check available space
    auto available_space = adaptor.size();

    // 3. Calculate the total required size: sizeof(header) + items.size() * sizeof(uint32_t)
    auto required_size = sizeof(header) + items.size() * sizeof(uint32_t);

    // 4. If available space is insufficient, return false
    if (available_space < required_size) {
        return false;
    }

    // 5. Otherwise, get the write pointer using buffer_adaptor's write_ptr()
    auto write_ptr = adaptor.write_ptr();

    // 6. Write the header using binary_stream's operator<<
