        return {}; // Return empty vector if file error or insufficient data
    }

    std::vector<uint8_t> preview(bytes_to_preview);
    buffer.copy(preview.data(), bytes_to_preview);

    if (buffer.error()) {
        return {}; // Return empty vector if copy error occurred
