```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer was created successfully
    if (!buffer) {
        return {}; // Return empty vector on error
    }

    // Get the available data size using the size() method
    auto available_size = buffer.size();

    // Calculate the actual read size (minimum of requested header_size and available size)
    size_t read_size = (header_size > available_size) ? available_size : header_size;

    // Create a destination buffer (std::vector<uint8_t>) with the calculated size
    std::vector<uint8_t> header_data(read_size);

    // Use the copy() method to read data without advancing the read pointer
    buffer.copy(header_data.data(), read_size);

    // Return the vector containing the header data
    return header_data;
}
```

