#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Write the container size as a uint32_t in little-endian format
    writer << static_cast<uint32_t>(container.size());

    // Write the container elements using the put method for contiguous containers
    writer.put(container.data(), container.size());
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    std::vector<uint32_t> result;

    // Read the container size as a uint32_t in little-endian format
    uint32_t size = 0;
    reader >> size;

    // Read the container elements using the get method for contiguous containers
    if (size > 0) {
        result.resize(size);
        reader.get(result.data(), size);
    }

    return result;
}
```

## Explanation:

### `write_container_to_stream` function:
1. **Write container size**: Uses the stream insertion operator `<<` to write the container size as a `uint32_t` in little-endian format, as specified in the assessment objectives.
2. **Write container elements**: Uses the `put` method with the container's data pointer and size to efficiently write all elements in one operation, leveraging the contiguous memory layout of `std::vector`.

### `read_container_from_stream` function:
1. **Read container size**: Uses the stream extraction operator `>>` to read the size as a `uint32_t` in little-endian format.
2. **Read container elements**: 
   - Resizes the result vector based on the read size
   - Uses the `get` method with the vector's data pointer to read all elements efficiently
   - Handles the case where size is 0 by returning an empty vector

Both implementations correctly use the `binary_stream_writer` and `binary_stream_reader` APIs as specified in the reference materials, and follow the exact requirements outlined in the assessment objectives.

