```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor and write data
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> write_adaptor(buffer);

    // Check available space before writing
    if (write_adaptor.free() < input_data.size()) {
        // Resize buffer if needed (implementation depends on specific requirements)
        // For this example, we'll resize to accommodate the data
        buffer.resize(input_data.size() + 100); // Add some padding
        write_adaptor = hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>>(buffer);
    }

    // Write the input data to the buffer
    write_adaptor.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor and read data back
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check readable size before reading
    if (read_adaptor.size() != input_data.size()) {
        throw std::runtime_error("Readable size mismatch");
    }

    std::vector<uint8_t> output_data(input_data.size());
    read_adaptor.read(output_data.data(), output_data.size());

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer_data);

    // Use copy() to peek at data without advancing the read pointer
    std::vector<uint8_t> peek_buffer(peek_size);
    adaptor.copy(peek_buffer.data(), peek_size);

    // Use read_ptr() to get pointer to current read position
    const uint8_t* current_read_ptr = adaptor.read_ptr();

    // Use read() to actually consume the data
    std::vector<uint8_t> consumed_data(peek_size);
    adaptor.read(consumed_data.data(), peek_size);

    return consumed_data;
}
